export async function POST() {
  try {
    await supabase.from("mikiwame_results").delete().neq("id", "00000000-0000-0000-0000-000000000000");
    const batchSize = 50;
    let inserted = 0;
    for (let i = 0; i < MIKIWAME_DATA.length; i += batchSize) {
      const batch = MIKIWAME_DATA.slice(i, i + batchSize);
      const { error } = await supabase.from("mikiwame_results").insert(batch);
      if (error) throw error;
      inserted += batch.length;
    }
    return NextResponse.json({ success: true, count: inserted });
  } catch (error: unknown) {
    const msg = error instanceof Error ? error.message : JSON.stringify(error);
    return NextResponse.json({ error: msg }, { status: 500 });
  }
}
